package com.km.el.bmi;import javax.servlet.http.HttpServletRequest;public class BmiModel {    public static void bmi(HttpServletRequest request) {        try {            String n = request.getParameter("name");            double h = Double.parseDouble(request.getParameter("height"));            double hh = h/100;            double w = Double.parseDouble(request.getParameter("weight"));            double result = w / (hh * hh);            String judge = "";            if (result < 18.5) {                judge = "저체중";            } else if (result <= 22.9) {                judge = "정상";            } else if (result <= 24.9) {                judge = "과체중 (비만 전 단계)";            } else if (result <= 29.9) {                judge = "1단계 비만";            } else if (result <= 34.9) {                judge = "2단계 비만";            } else if (result >= 35.0) {                judge = "3단계 비만 (고도비만)";            }            BmiVO bmiVO = new BmiVO();            bmiVO.setName(n);            bmiVO.setHeight(h);            bmiVO.setWeight(w);            bmiVO.setResult(result);            bmiVO.setJudge(judge);            BmiVO bmiVO2 = new BmiVO(n, h, w, result, judge);            request.setAttribute("bmiVO", bmiVO);        } catch (Exception e) {            e.printStackTrace();        }    }}